const loadSwapHistory = async () => {
  if (!address) return

  try {
    const { requests } = await relayAPI.getRequests({
      user: address,
      limit: 20,
      sortBy: 'createdAt',
      sortDirection: 'desc',
    })

    const history: SwapHistory[] = requests.map(req => {
      console.log('Processing request:', req.id, req)

      // Get chain IDs from transactions
      const originChainId = req.data.inTxs?.[0]?.chainId
      const destChainId = req.data.outTxs?.[0]?.chainId

      const originChain = chains.find(c => c.id === originChainId)
      const destChain = chains.find(c => c.id === destChainId)

      // Extract currency information from the request details
      const currencyIn = req.details?.currencyIn
      const currencyOut = req.details?.currencyOut

      // Get amounts from details (more accurate than raw transaction values)
      let fromAmount = '0'
      let toAmount = '0'
      let fromDecimals = 18
      let toDecimals = 18
      let fromSymbol = 'Unknown'
      let toSymbol = 'Unknown'

      if (currencyIn) {
        fromAmount = currencyIn.amountFormatted || '0'
        fromDecimals = currencyIn.currency?.decimals || 18
        fromSymbol = currencyIn.currency?.symbol || 'Unknown'
      } else if (req.data.inTxs?.[0]) {
        // Fallback to transaction data
        const inTx = req.data.inTxs[0]
        const rawAmount = inTx.data?.value || inTx.value || '0'
        fromDecimals = inTx.currency?.decimals || 18
        fromSymbol = inTx.currency?.symbol || originChain?.currency?.symbol || 'Unknown'

        if (rawAmount && rawAmount !== '0') {
          try {
            fromAmount = parseFloat(formatUnits(BigInt(rawAmount), fromDecimals)).toFixed(6)
          } catch (e) {
            fromAmount = rawAmount
          }
        }
      }

      if (currencyOut) {
        toAmount = currencyOut.amountFormatted || '0'
        toDecimals = currencyOut.currency?.decimals || 18
        toSymbol = currencyOut.currency?.symbol || 'Unknown'
      } else if (req.data.outTxs?.[0]) {
        // Fallback to transaction data
        const outTx = req.data.outTxs[0]
        const rawAmount = outTx.data?.value || outTx.value || '0'
        toDecimals = outTx.currency?.decimals || 18
        toSymbol = outTx.currency?.symbol || destChain?.currency?.symbol || 'Unknown'

        if (rawAmount && rawAmount !== '0') {
          try {
            toAmount = parseFloat(formatUnits(BigInt(rawAmount), toDecimals)).toFixed(6)
          } catch (e) {
            toAmount = rawAmount
          }
        }
      }

      return {
        id: req.id,
        fromToken: currencyIn?.currency?.address || req.data.inTxs?.[0]?.currency?.address || '0x0',
        fromTokenSymbol: fromSymbol,
        fromTokenDecimals: fromDecimals,
        toToken: currencyOut?.currency?.address || req.data.outTxs?.[0]?.currency?.address || '0x0',
        toTokenSymbol: toSymbol,
        toTokenDecimals: toDecimals,
        fromAmount,
        toAmount,
        fromChain: originChain?.displayName || originChain?.name || 'Unknown',
        fromChainId: originChainId || 0,
        fromChainIcon: originChain?.iconUrl,
        toChain: destChain?.displayName || destChain?.name || 'Unknown',
        toChainId: destChainId || 0,
        toChainIcon: destChain?.iconUrl,
        status: req.status,
        timestamp: new Date(req.createdAt).getTime(),
        completedAt: req.completedAt ? new Date(req.completedAt).getTime() : undefined,
        txHash: req.data.outTxs?.[0]?.hash,
        inTxHash: req.data.inTxs?.[0]?.hash,
      }
    })

    setSwapHistory(history)
  } catch (error) {
    console.error('Failed to load swap history:', error)
  }
}
